                  text: yhLang(
                    "Do not seek treatment from traditional healers or apply herbal remedies.",
                    "স্থানীয় কবিরাজ বা ওঝার কাছে চিকিৎসা নেয়া অথবা কোনো ভেষজ ওষুধ প্রয়োগ করা যাবে না।",
                  ),
                  icon: "fa-leaf",
                  color: "m18l6-step-remedy",
